const staticData = $getWorkflowStaticData('node');

const attempts = staticData.attempts ?? 0;
const newAttempts = attempts + 1;

if (newAttempts >= 3) {
    staticData.attempts = 0; // reset for next execution
    return [{ json: { ...$json, attempts: newAttempts, is_failed: 'yes' } }];
}

staticData.attempts = newAttempts;
return [{ json: { ...$json, attempts: newAttempts, is_failed: 'no' } }];

const output = $json.output || '';

const requiredKeywords = [
    ['Internal', 'Risques internes', 'Internes'],
    ['External', 'Risques externes', 'Externes'],
    ['Mitigation', 'Mitigation'],
    ['Opportunity', 'Opportunités', 'Opportunité'],
];

const missingKeywords = requiredKeywords.filter(group =>
    !group.some(kw => output.toLowerCase().includes(kw.toLowerCase()))
);

return [{
    json: {
        ...$json,
        keywords_valid: missingKeywords.length === 0 ? 'true' : 'false',
        missing_keywords: missingKeywords.map(g => g[0]),
    }
}];

const output = $json.output || '';
const minLength = 400;
const length_valid = output.length >= minLength ? 'true' : 'false';

return [{
  json: {
    ...$json,
    length_valid: length_valid,
    actual_length: output.length,
  }
}];

const body = $json.body || $json;
const sectionId = body.section_id;
const input = body.input_json || {};
const context = body.plan_context || {};
const language = body.language || 'english';
const businessPlanId = body.business_plan_id;

const headings = language === 'french' ? `
- Risques internes
- Risques externes
- Plans de mitigation
- Opportunités
` : `
- Internal Risks
- External Risks
- Mitigation Plans
- Opportunities
`;

// Pass only MEMORY_SUMMARY from financial context — not full prose
const financialContext = context.financial_plan || 'Not provided';

const prompt = `
You are a senior risk management consultant writing a professional business plan.

Your task: Write the "Risk & Opportunity Analysis" section of a business plan.
Output language: ${language}

## COMPANY CONTEXT
${context.company_presentation || 'Not provided'}

## MARKET CONTEXT
${context.market_analysis || 'Not provided'}

## STRATEGY CONTEXT
${context.strategy || 'Not provided'}

## OPERATIONAL CONTEXT
${context.operational_plan || 'Not provided'}

## FINANCIAL CONTEXT (authoritative figures — reference these exact numbers)
${financialContext}

## RISK INPUT DATA
- Internal Risks: ${input.internal_risks || 'Not provided'}
- External Risks: ${input.external_risks || 'Not provided'}
- Mitigation Plans: ${input.mitigation_plans || 'Not provided'}
- Opportunities: ${input.opportunities || 'Not provided'}
- Contingency Plan: ${input.contingency || 'Not provided'}

## RULES
- Use ONLY the data provided above. Do NOT invent risks, probabilities, or mitigation strategies.
- For any field marked "Not provided", derive a plausible risk or opportunity directly from the context sections above and integrate it naturally into the prose. Do NOT add any label such as "Identified from business context:" — derived insights must read as seamless analysis.
- Every risk MUST be paired with a mitigation action. If none was provided, derive one from the strategy or operational context.
- Every opportunity MUST be connected to a specific market trend, competitive gap, or operational capability already described in the context.
- Risks and opportunities MUST be specific to this company's industry, location, and business model — not generic.
- Financial figures cited MUST match the Financial Context above exactly.
- Write at least 400 words.
- Use formal, analytical business language throughout.
- Structure the section using these headings: ${headings}
- NEVER repeat a sentence, phrase, or paragraph already written earlier in your response. Each paragraph MUST introduce new information.

## OUTPUT FORMAT
Return your response using EXACTLY this structure. Nothing before. Nothing after.

=== SECTION_TEXT ===
[Write the full Risk & Opportunity Analysis section here, using the headings above]

=== MEMORY_SUMMARY ===
Top Internal Risk: [single most critical internal risk in 1 sentence]
Top External Risk: [single most critical external risk in 1 sentence]
Mitigation: [primary mitigation approach in 1 sentence]
Top Opportunity: [single highest-impact opportunity in 1 sentence]
Contingency: [value or "Not provided"]
`;

return [{
  json: {
    prompt,
    sectionId: sectionId,
    business_plan_id: businessPlanId,
    section_name: 'risk_opportunity',
    language,
    input_json: input,
  }
}];

const raw = $('AI Agent').item.json.output || '';

let textMatch = raw.match(/=== SECTION_TEXT ===([\s\S]*?)=== MEMORY_SUMMARY ===/);
let memMatch  = raw.match(/=== MEMORY_SUMMARY ===([\s\S]*?)$/);

if (!textMatch) {
  const parts = raw.split(/===\s*MEMORY_SUMMARY\s*===/i);
  textMatch = parts.length > 1 ? [null, parts[0].replace(/===.*?===/i, '').trim()] : null;
}
if (!memMatch) {
  const parts = raw.split(/===\s*MEMORY_SUMMARY\s*===/i);
  memMatch = parts.length > 1 ? [null, parts[1].trim()] : null;
}

let section_text   = textMatch ? textMatch[1].replace(/^===.*?===\n?/i, '').trim() : raw.trim();
section_text = section_text.replace(/===\s*[^=]*?\s*===/g, '').trim();
const memory_summary = memMatch ? memMatch[1].trim() : '';

const promptText   = $('Build Prompt').item.json.prompt || '';
const tokens_input  = Math.round(promptText.length / 4);
const tokens_output = Math.round(raw.length / 4);
const tokens_total  = tokens_input + tokens_output;

const buildData = $('Build Prompt').item.json;
return [{
  json: {
    ...buildData,
    output: section_text,
    memory_summary,
    tokens_input,
    tokens_output,
    tokens_total,
  }
}];
